/**
 * 基于关键词在文本中匹配符号（规则降级解析用）。
 * 返回匹配到的符号数组，含命中关键词数与解读说明。
 */
export function matchSymbols(text: string): DreamSymbol[] {
  if (!text) return [];
  const result: DreamSymbol[] = [];
  for (const sym of SYMBOLS) {
    let hitCount = 0;
    let hitKeyword = '';
    for (const kw of sym.keywords) {
      if (text.includes(kw)) {
        hitCount += 1;
        if (!hitKeyword) hitKeyword = kw;
      }
    }
    if (hitCount > 0) {
      const note = sym.interpretations[0]?.meaning ?? sym.name;
      result.push({
        name: sym.name,
        // 概率由调用方进一步估算，这里先给一个保守值
        probability: Math.min(0.5 + hitCount * 0.1, 0.7),
        note,
      });
    }
  }
  return result;
}

/** 按名查找符号条目 */
export function getSymbolByName(name: string): SymbolEntry | undefined {
  return SYMBOLS.find((s) => s.name === name);
}
